import json, csv, datetime
import pandas as pd

FIELD_MAP = {
    'user_id':'user_id','id':'user_id','userId':'user_id',
    'email':'email','email_address':'email',
    'full_name':'name','name':'name','userName':'name',
    'registration_date':'created_date','created_at':'created_date','joined':'created_date',
    'status':'status',
}

def norm_date(v):
    if v is None: return None
    s=str(v).strip()
    if not s: return None
    for f in ('%Y-%m-%d','%Y/%m/%d','%m/%d/%Y','%d-%m-%Y','%Y-%m-%dT%H:%M:%S','%Y-%m-%d %H:%M:%S'):
        try: return datetime.datetime.strptime(s,f).strftime('%Y-%m-%d')
        except ValueError: pass
    try: return pd.to_datetime(s).strftime('%Y-%m-%d')
    except Exception: return s

def remap(rec):
    out={}
    for k,v in rec.items():
        if k in FIELD_MAP:
            out[FIELD_MAP[k]]=v
    if 'user_id' in out and out['user_id'] is not None:
        out['user_id']=int(out['user_id'])
    if 'created_date' in out:
        out['created_date']=norm_date(out['created_date'])
    for f in ('name','email'):
        if f in out and out[f] is not None:
            out[f]=str(out[f])
    if 'status' in out and out['status'] is not None:
        out['status']=str(out['status'])
    return out

# source_a
with open('/data/source_a/users.json') as f:
    a=[remap(r) for r in json.load(f)]
# source_b
b=[]
with open('/data/source_b/users.csv') as f:
    for r in csv.DictReader(f):
        b.append(remap(r))
# source_c
cdf=pd.read_parquet('/data/source_c/users.parquet')
c=[remap({k:(None if pd.isna(v) else v) for k,v in row.items()}) for row in cdf.to_dict('records')]

sources={'source_a':a,'source_b':b,'source_c':c}
priority=['source_a','source_b','source_c']

by_user={}  # uid -> {src: rec}
for src in priority:
    for rec in sources[src]:
        uid=rec.get('user_id')
        if uid is None: continue
        by_user.setdefault(uid,{})[src]=rec

FIELDS=['name','email','created_date']
merged=[]
conflicts=[]
for uid in sorted(by_user):
    smap=by_user[uid]
    out={'user_id':uid}
    for field in FIELDS+['status']:
        for src in priority:
            if src in smap and smap[src].get(field) is not None:
                out[field]=smap[src][field]; break
        else:
            out[field]=None
    merged.append(out)
    # conflict detection over mapped fields
    for field in FIELDS:
        vals={src:smap[src].get(field) for src in priority if src in smap and smap[src].get(field) is not None}
        if len(set(vals.values()))>1:
            conflicts.append({
                'user_id':uid,'field':field,
                'values':vals,'selected':out[field],
            })

mdf=pd.DataFrame(merged,columns=['user_id','name','email','created_date','status'])
mdf['user_id']=mdf['user_id'].astype('int64')
for col in ('name','email','created_date','status'):
    mdf[col]=mdf[col].astype('object')
mdf.to_parquet('/app/merged_users.parquet',index=False)

report={'total_conflicts':len(conflicts),'conflicts':conflicts}
with open('/app/conflicts.json','w') as f:
    json.dump(report,f,indent=2)

print(mdf.to_string())
print('conflicts',len(conflicts))
print(json.dumps(report,indent=2)[:1500])
EOF
